VALUES
  ('social-worker-moex-05360', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Shonkoff與Phillips（2000）研究嬰幼兒對於強烈情緒發展會建立一套處理方式，如積極避免、漠視會引 起強烈情緒的情境，並進行自我的安慰。研究發現除了嬰兒的先天氣質與受到照顧者對於情緒管理所提 供的協助外，應再重視與評估何者因素？', '["世代效應對情緒管理的影響", "政策對情緒管理的影響", "同儕對情緒管理的期待", "文化對情緒管理的期待"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "244cfe4f41a8", "answer_pdf_sha1": "f1f4e7d2636b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05361', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Davies（2004）認為嬰幼兒會抱緊著一床毯子、玩具熊，或是填充玩偶來幫助他們處理父母／照顧者分離 或其他緊張的情況，這被認為是與照顧者關係的象徵，Davies稱之為：', '["過渡性客體（transitional objects）", "情緒的象徵（emotional symbolic）", "互動的象徵（interactional symbolic）", "互動的客體（interactional objects）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "244cfe4f41a8", "answer_pdf_sha1": "f1f4e7d2636b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05362', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列敘述，何者錯誤？', '["Labouvie-Vief（1994）認為成年前期的成人較能駕馭形式運思能力，以較客觀的方式解決問題，會有 比較務實的態度，在思考上更具彈性與多樣性", "「選擇性優化」（selective optimization）是針對成年晚期的老人認知相關的理論之一，認為老人能選擇 重要的任務和活動相關的資訊，捨棄其他不重要的；並努力讓自己的技巧和優勢發揮到最大的效能", "Vallant（1977）認為成年中期的重要課題之一在於意義的追尋，避免流於剛愎與停滯", "Maas（1989）認為成年前期是開始思考他人福祉的階段，並且是具備實踐社會責任能力的階段"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "244cfe4f41a8", "answer_pdf_sha1": "f1f4e7d2636b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05363', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「著重人格重新重組，著重智慧成就及自我省思，以獲得創生感（generativity）」是 Erikson（1963）心 理社會發展理論觀點的那個時期？', '["青少年期", "成年前期", "中年期", "成年晚期"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "244cfe4f41a8", "answer_pdf_sha1": "f1f4e7d2636b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05364', 'social-worker', 'social-worker-moex-106-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Castells（2002）主張任何的認同感都具有社會性或社會層面，都是社會建構而成。他將認同分為三種類 型，下列何者錯誤？', '["正當性的認同（legitimation identity）", "抵抗性認同（resistance identity）", "情感性認同（emotion identity）", "計畫性認同（project identity）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "244cfe4f41a8", "answer_pdf_sha1": "f1f4e7d2636b", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05365', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列敘述何者沒有語病？', '["花蓮洄瀾灣文化廣場，明年正式招商", "政府應該公開詳細的環評結果，才能信服百姓", "世界網壇，女網小威廉斯稱王，男網喬科維奇封后", "一輛急駛的轎車從背後迎面而來，將老先生撞個正著"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05366', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「我們現代人的苦惱是新現象新問題層出不窮，舊經驗舊方法難以因應。可是快樂 也在這裏：社會在成長，才會有新現象新問題出現，我們也在成長，才會跟這些現 象和問題接觸，解釋這些現象、解決這些問題，才會成為我們的責任。」根據上文， 要能適應現代社會的變化，最需要的人格特質是：', '["先聲奪人", "居安思危", "革故鼎新", "古道熱腸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05367', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列語詞使用，正確的選項是：', '["此處於10月8日全天將有路跑活動，特此知悉", "本公司週日將舉辦公益慶生活動，惠賜蒞臨指導", "狂犬病防治方案如附件，為資周妥，請惠示卓見，俾憑辦理", "本科訂於106年2月10日假會議室舉辦座談會，敬請卓參光臨"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05368', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '景公獵休，坐地而食，晏子後至，左右滅葭而席。公不說，曰：「寡人不席而坐地， 二三子莫席，而子獨搴草而坐之，何也？」晏子對曰：「臣聞介冑坐陳不席，獄訟 不席，尸坐堂上不席，三者皆憂也。故不敢以憂侍坐。」公曰：「諾。」令人下席 曰：「大夫皆席，寡人亦席矣。」 下列選項何者最能形容晏子的表現？', '["公忠體國，慈悲為懷", "明慎所職，婉言勸諫", "能言善道，以德服人", "潔身自好，明哲保身"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05369', 'social-worker', 'social-worker-moex-106-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '《論語．為政》：「吾十有五而志於學；三十而立；四十而不惑；五十而知天命； 六十而耳順；七十而從心所欲不踰矩。」下列選項何者最接近孔子七十歲以後的生 命境界？', '["縱浪大化，脫略形骸", "謹守規矩，唯恐踰越", "淡泊自守，砥礪風節", "一言一動，悉合於道"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "66c4a9d660ec", "answer_pdf_sha1": "54a42acd5517", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
